     1→/**
     2→ * Enhanced Stroop Task using new FluentExperimentBuilder API
     3→ * Demonstrates power analysis, type-safe conditions, and FZB compilation
     4→ */
     5→
     6→import { 
     7→  experiment, 
     8→  conditions, 
     9→  trial,
    10→  compileExperiment,
    11→  type PowerAnalysisOptions 
    12→} from '../src/index.js';
    13→
    14→// Define our experimental conditions with type safety
    15→interface StroopCondition {
    16→  word: string;
    17→  color: string;
    18→  congruent: boolean;
    19→}
    20→
    21→async function createEnhancedStroopTask() {
    22→  console.log('🧠 Creating Enhanced Stroop Task with Power Analysis...');
    23→
    24→  // Configure power analysis for a medium effect size in an ANOVA
    25→  const powerConfig: PowerAnalysisOptions = {
    26→    effectSize: 0.5, // Medium effect size (Cohen's f)
    27→    power: 0.8,      // 80% power
    28→    alpha: 0.05,     // 5% significance level
    29→    testType: 'anova',
    30→    groups: 2,       // Congruent vs Incongruent
    31→  };
    32→
    33→  // Build experiment with fluent API and validation
    34→  const experimentBuilder = experiment('enhanced-stroop-task')
    35→    .title('Enhanced Stroop Task with Power Analysis')
    36→    .description('Advanced Stroop task demonstrating type-safe conditions and power analysis')
    37→    .version('2.0.0')
    38→    .author('ForgeScript Team')
    39→    .institution('Psycho-Forge Research Lab')
    40→    .tags(['stroop', 'attention', 'cognitive-control', 'interference'])
    41→    .requirePower(powerConfig)
    42→    .backgroundColor('#f0f0f0')
    43→    .fullScreen(true)
    44→    .strict(true)           // Enable strict validation
    45→    .optimize(true)         // Enable optimization
    46→    .enableVerification(true); // Enable formal verification
    47→
    48→  // Calculate required sample size
    49→  const powerAnalysis = experimentBuilder.calculateSampleSize();
    50→  console.log('📊 Power Analysis Results:');
    51→  console.log(`  Required sample size: ${powerAnalysis.sampleSize}`);
    52→  console.log(`  Statistical power: ${powerAnalysis.power}`);
    53→  console.log(`  Effect size: ${powerAnalysis.effectSize}`);
    54→  console.log(`  Recommendations:`);
    55→  powerAnalysis.recommendations.forEach(rec => console.log(`    - ${rec}`));
    56→
    57→  // Create type-safe experimental conditions
    58→  const stroopConditions = conditions<StroopCondition>()
    59→    .factor('word', ['RED', 'GREEN', 'BLUE', 'YELLOW'])
    60→    .factor('color', ['red', 'green', 'blue', 'yellow'])
    61→    .repeat(5) // 5 repetitions per condition
    62→    .randomize(42) // Seeded randomization for reproducibility
    63→    .build()
    64→    .map(condition => ({
    65→      ...condition,
    66→      congruent: condition.word.toLowerCase() === condition.color
    67→    }));
    68→
